3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const FIRST_INSURANCE_PERCENT = 110;
13	const PROCESSING_FEE = 5;
14	
15	type Item = { type: string; cursed?: boolean; enchantment?: number };
16	
17	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
18	const BLOCK_OF_3_BASE_PREMIUM = 60;
19	const BLOCK_OF_3_SIZE = 3;
20	const CURSED_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	
24	const isBlockOf3Components = (type: string, count: number): boolean =>
25	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
26	
27	const baseForGroup = (type: string, count: number): number =>
28	  isBlockOf3Components(type, count)
29	    ? BLOCK_OF_3_BASE_PREMIUM
30	    : BASE_PREMIUMS[type] * count;
31	
32	const countItemsByType = (items: Item[]): Record<string, number> =>
33	  items.reduce<Record<string, number>>((counts, item) => {
34	    counts[item.type] = (counts[item.type] ?? 0) + 1;
35	    return counts;
36	  }, {});
37	
38	const baseTotalFor = (items: Item[]): number =>
39	  Object.entries(countItemsByType(items))
40	    .reduce((total, [type, count]) => total + baseForGroup(type, count), 0);
41	
42	const surchargeOnBase = (item: Item, applies: boolean, rate: number): number =>
43	  applies ? BASE_PREMIUMS[item.type] * rate : 0;
44	
45	const cursedSurchargeFor = (item: Item): number =>
46	  surchargeOnBase(item, item.cursed === true, CURSED_SURCHARGE_RATE);
47	
48	const highEnchantmentSurchargeFor = (item: Item): number =>
49	  surchargeOnBase(item, (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE_RATE);
50	
51	const itemSurchargesFor = (items: Item[]): number =>
52	  items.reduce((total, item) => total + cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
53	
54	const quotePremium = (items: Item[]): number => {
55	  const baseTotal = baseTotalFor(items);
56	  const withFirstInsurance = (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
57	  return Math.ceil(withFirstInsurance + itemSurchargesFor(items) + PROCESSING_FEE);
58	};
59	
60	export function processScenario(scenario: any): unknown {
61	  const [{ items }] = scenario.steps;
62	  return { results: [{ premium: quotePremium(items) }] };
63	}
